function normalizeApprovalExpiryDuration(fieldName, rawValue, defaultDuration) {
    // If missing, use default
    if (rawValue === undefined || rawValue === null || rawValue === "") {
        return {
            value: defaultDuration.value,
            unit: defaultDuration.unit,
            display: defaultDuration.unit + "(s)"
        };
    }

    // Backward-compat (older callers): if a bare number is provided, treat it as HOURS.
    if (typeof rawValue === "number" || (typeof rawValue === "string" && rawValue !== "" && isFinite(Number(rawValue)))) {
        var nHours = Number(rawValue);
        if (!isFinite(nHours) || Math.floor(nHours) !== nHours || nHours <= 0) {
            throw { code: 400, message: fieldName + " must be a positive integer (or {value, unit})" };
        }
        return { value: nHours, unit: "hour", display: "hour(s)" };
    }

    // Expected structure: { value: <int>, unit: <string> }
    if (typeof rawValue !== "object") {
        throw { code: 400, message: fieldName + " must be an object with attributes { value, unit }" };
    }

    var v = rawValue.value;
    var u = rawValue.unit;

    if (v === undefined || v === null || v === "") {
        throw { code: 400, message: fieldName + ".value is required and must be a positive integer" };
    }
    var n = Number(v);
    if (!isFinite(n) || Math.floor(n) !== n) {
        throw { code: 400, message: fieldName + ".value must be a positive integer" };
    }
    if (n <= 0) {
        throw { code: 400, message: fieldName + ".value must be > 0" };
    }

    if (u === undefined || u === null || u === "") {
        throw { code: 400, message: fieldName + ".unit is required (minute|hour|day|week|month)" };
    }

    var unit = String(u).toLowerCase().replace(/^\s+|\s+$/g, "");
    if (unit.length > 0 && unit.substring(unit.length - 1) === "s") {
        unit = unit.substring(0, unit.length - 1); // accept "hours", "days", etc.
    }

    // Canonicalize + validate
    var allowed = { minute: true, hour: true, day: true, week: true, month: true };
    if (!allowed[unit]) {
        throw { code: 400, message: fieldName + ".unit must be one of: minute, hour, day, week, month" };
    }

    return { value: n, unit: unit, display: unit + "(s)" };
}

function buildExpirationIsoExpr(value, unit) {
    // Use Date arithmetic; months are handled with setMonth because month length varies.
    if (unit === "month") {
        return "(function(){var d=new Date(); d.setMonth(d.getMonth()+(" + value + ")); return d.toISOString();})()";
    }

    var msPerUnit = {
        minute: 60 * 1000,
        hour: 60 * 60 * 1000,
        day: 24 * 60 * 60 * 1000,
        week: 7 * 24 * 60 * 60 * 1000
    };

    return "(new Date(new Date().getTime()+(" + value + "*" + msPerUnit[unit] + "))).toISOString()";
}

